import React from 'react';
import { Linking, Platform } from 'react-native';
import * as navigationRef from './NavigationRef'; // Custom navigation ref
import { useDispatch } from 'react-redux';
import { navigate } from './Navigator'; // Navigation actions

const linking = {
  prefixes: [Platform.OS === 'ios' ? 'myapp://' : 'myapp://'],
  config: {},
};

Linking.addEventListener('url', handleOpenURL);

function handleOpenURL(event) {
  const url = event.url;
  let routeName = '';

  if (url.includes('/profile/')) {
    routeName = 'ProfileScreen';
  } else if (url.includes('/payment/confirm')) {
    routeName = 'PaymentConfirmScreen';
  }

  if (routeName) {
    dispatch(navigate(routeName));
  }
}

function App() {
  const dispatch = useDispatch();

  Linking.getInitialURL().then((url) => {
    handleOpenURL({ url });
  });

  return (
    // Your app's JSX structure here, make sure to wrap it with navigation ref for easy navigation
    <NavigationRef.Navigator>...</NavigationRef.Navigator>
  );
}